const express = require('express');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());

// In-memory data store for demonstration
let items = [
  { id: 1, name: 'Item One', description: 'This is the first item' },
  { id: 2, name: 'Item Two', description: 'This is the second item' },
];

/**
 * GET /api/items
 * Returns a list of all items
 */
app.get('/api/items', (req, res) => {
  res.status(200).json(items);
});

/**
 * GET /api/items/:id
 * Returns a single item by ID
 */
app.get('/api/items/:id', (req, res) => {
  const item = items.find(i => i.id === parseInt(req.params.id));
  if (!item) return res.status(404).json({ message: 'Item not found' });
  res.status(200).json(item);
});

/**
 * POST /api/items
 * Creates a new item
 */
app.post('/api/items', (req, res) => {
  const { name, description } = req.body;
  if (!name) return res.status(400).json({ message: 'Name is required' });

  const newItem = {
    id: items.length + 1,
    name,
    description: description || ''
  };
  items.push(newItem);
  res.status(201).json(newItem);
});

/**
 * PUT /api/items/:id
 * Updates an existing item
 */
app.put('/api/items/:id', (req, res) => {
  const item = items.find(i => i.id === parseInt(req.params.id));
  if (!item) return res.status(404).json({ message: 'Item not found' });

  const { name, description } = req.body;
  item.name = name || item.name;
  item.description = description || item.description;

  res.status(200).json(item);
});

/**
 * DELETE /api/items/:id
 * Removes an item from the store
 */
app.delete('/api/items/:id', (req, res) => {
  const index = items.findIndex(i => i.id === parseInt(req.params.id));
  if (index === -1) return res.status(404).json({ message: 'Item not found' });

  const deletedItem = items.splice(index, 1);
  res.status(200).json({ message: 'Item deleted successfully', item: deletedItem[0] });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

const express = require('express');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const app = express();

app.use(express.json());

const SECRET_KEY = 'your_super_secret_key'; // In production, use process.env.JWT_SECRET
const users = []; // Mock database

// --- AUTHENTICATION MIDDLEWARE ---
const authenticateToken = (req, res, next) => {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (!token) return res.status(401).json({ message: 'Access Token Required' });

    jwt.verify(token, SECRET_KEY, (err, user) => {
        if (err) return res.status(403).json({ message: 'Invalid or Expired Token' });
        req.user = user;
        next();
    });
};

// --- AUTHORIZATION MIDDLEWARE ---
const authorizeRole = (role) => {
    return (req, res, next) => {
        if (req.user.role !== role) {
            return res.status(403).json({ message: 'Forbidden: Insufficient Permissions' });
        }
        next();
    };
};

// --- ROUTES ---

// Register
app.post('/api/auth/register', async (req, res) => {
    try {
        const { username, password, role } = req.body;
        const hashedPassword = await bcrypt.hash(password, 10);
        const user = { username, password: hashedPassword, role: role || 'user' };
        users.push(user);
        res.status(201).json({ message: 'User registered successfully' });
    } catch (error) {
        res.status(500).json({ message: 'Registration failed' });
    }
});

// Login
app.post('/api/auth/login', async (req, res) => {
    const { username, password } = req.body;
    const user = users.find(u => u.username === username);

    if (!user || !(await bcrypt.compare(password, user.password))) {
        return res.status(401).json({ message: 'Invalid credentials' });
    }

    const token = jwt.sign(
        { username: user.username, role: user.role },
        SECRET_KEY,
        { expiresIn: '1h' }
    );
    res.json({ token });
});

// Protected Route (Any authenticated user)
app.get('/api/profile', authenticateToken, (req, res) => {
    res.json({ message: `Welcome ${req.user.username}`, user: req.user });
});

// Admin Only Route
app.get('/api/admin', authenticateToken, authorizeRole('admin'), (req, res) => {
    res.json({ message: 'Welcome to the Admin Dashboard' });
});

app.listen(3000, () => console.log('Server running on port 3000'));

import unittest
import json
from flask import Flask, request, jsonify

# --- Application Code (The API to be tested) ---
app = Flask(__name__)

# Mock Database
data_store = {
    1: {"name": "Item One", "description": "This is item one"},
    2: {"name": "Item Two", "description": "This is item two"}
}

@app.route('/api/items/<int:item_id>', methods=['GET'])
def get_item(item_id):
    item = data_store.get(item_id)
    if item:
        return jsonify(item), 200
    return jsonify({"error": "Item not found"}), 404

@app.route('/api/items', methods=['POST'])
def create_item():
    content = request.json
    if not content or 'name' not in content:
        return jsonify({"error": "Invalid data"}), 400

    new_id = max(data_store.keys()) + 1 if data_store else 1
    data_store[new_id] = content
    return jsonify({"id": new_id, "status": "created"}), 201

# --- Unit Tests ---
class TestRESTApi(unittest.TestCase):
    def setUp(self):
        # Configure app for testing
        app.config['TESTING'] = True
        self.client = app.test_client()
        # Reset mock data for isolation
        global data_store
        data_store = {
            1: {"name": "Item One", "description": "This is item one"},
            2: {"name": "Item Two", "description": "This is item two"}
        }

    def test_get_item_success(self):
        """Test retrieving an existing item"""
        response = self.client.get('/api/items/1')
        data = json.loads(response.data)

        self.assertEqual(response.status_code, 200)
        self.assertEqual(data['name'], "Item One")

    def test_get_item_not_found(self):
        """Test retrieving a non-existent item"""
        response = self.client.get('/api/items/999')
        data = json.loads(response.data)

        self.assertEqual(response.status_code, 404)
        self.assertEqual(data['error'], "Item not found")

    def test_create_item_success(self):
        """Test creating a new item with valid data"""
        payload = {"name": "Item Three", "description": "New item"}
        response = self.client.post('/api/items', 
                                    data=json.dumps(payload), 
                                    content_type='application/json')
        data = json.loads(response.data)

        self.assertEqual(response.status_code, 201)
        self.assertEqual(data['status'], "created")
        self.assertIn('id', data)

    def test_create_item_failure(self):
        """Test creating an item with missing required fields"""
        payload = {"description": "Missing name"}
        response = self.client.post('/api/items', 
                                    data=json.dumps(payload), 
                                    content_type='application/json')

        self.assertEqual(response.status_code, 400)
        self.assertIn("error", json.loads(response.data))

if __name__ == '__main__':
    unittest.main()
